# Base shapes module - defines abstract base classes and interfaces

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

@abstract
class Drawable:
    @abstract
    def draw(self) -> str: ...

interface ITransformable:
    def scale(self, factor: float) -> None
    def translate(self, dx: float, dy: float) -> None

interface IMeasurable:
    def get_measurement(self) -> float

class ShapeUtils:
    @static
    def compare_areas(s1: Shape, s2: Shape) -> str:
        a1: float = s1.area()
        a2: float = s2.area()
        if a1 > a2:
            return s1.name + " is larger"
        elif a2 > a1:
            return s2.name + " is larger"
        return "Equal areas"

