# Utility module - enums, structs, and constants

enum Color:
    RED = 0
    GREEN = 1
    BLUE = 2
    YELLOW = 3

@static
class Constants:
    PI: float = 3.14159

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

class ColorUtility:
    @static
    def get_color_name(c: Color) -> str:
        if c == Color.RED:
            return "red"
        elif c == Color.GREEN:
            return "green"
        elif c == Color.BLUE:
            return "blue"
        return "yellow"

    @static
    def mix(c1: Color, c2: Color) -> Color:
        if c1 == Color.RED and c2 == Color.BLUE or c1 == Color.BLUE and c2 == Color.RED:
            return Color.YELLOW
        elif c1 == Color.YELLOW and c2 == Color.RED or c1 == Color.RED and c2 == Color.YELLOW:
            return Color.GREEN
        return Color.RED

