# Concrete model implementations with cross-module inheritance

from shapes import Shape, Drawable, ShapeUtils
from shapes import ITransformable
from utils import Color, Point, Constants

class Circle(Shape, Drawable, ITransformable):
    center: Point
    radius: float
    color: Color

    def __init__(self, name: str, center: Point, radius: float):
        super().__init__(name)
        self.center = center
        self.radius = radius
        self.color = Color.RED

    def area(self) -> float:
        return Constants.PI * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * Constants.PI * self.radius

    def draw(self) -> str:
        return "Circle(" + self.name + ")"

    def scale(self, factor: float) -> None:
        self.radius *= factor

    def translate(self, dx: float, dy: float) -> None:
        self.center.x += dx
        self.center.y += dy

class Rectangle(Shape, Drawable, ITransformable):
    top_left: Point
    width: float
    height: float

    def __init__(self, name: str, top_left: Point, width: float, height: float):
        super().__init__(name)
        self.top_left = top_left
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return "Rectangle(" + self.name + ")"

    def scale(self, factor: float) -> None:
        self.width *= factor
        self.height *= factor

    def translate(self, dx: float, dy: float) -> None:
        self.top_left.x += dx
        self.top_left.y += dy

class Square(Rectangle):
    def __init__(self, name: str, top_left: Point, side: float):
        super().__init__(name, top_left, side, side)

    def draw(self) -> str:
        return "Square(" + self.name + ")"
